// Step 1: Request OTP
const otpRes = await pm.sendRequest({
    method: 'POST',
    url: pm.variables.replaceIn('{{baseUrl}}/api/auth/buyer/request-otp'),
    header: {'Content-Type': 'application/json'},
    body: {mode: 'raw', raw: JSON.stringify({phoneNumber: '081111111111'})}
});
const otpJson = otpRes.json();
const otp = otpJson.data?.otp || '00000';
await sleep(500);
// Step 2: Verify OTP
const verifyRes = await pm.sendRequest({
    method: 'POST',
    url: pm.variables.replaceIn('{{baseUrl}}/api/auth/buyer/verify-otp'),
    header: {'Content-Type': 'application/json'},
    body: {mode: 'raw', raw: JSON.stringify({phoneNumber: '081111111111', otp: otp})}
});
const verifyJson = verifyRes.json();
if (verifyJson.data) {
    const accessToken = verifyJson.data.accessToken || verifyJson.data.token;
    const refreshToken = verifyJson.data.refreshToken || '';
    pm.collectionVariables.set('buyerToken', accessToken);
    if (refreshToken) pm.collectionVariables.set('refreshToken', refreshToken);
    if (verifyJson.data.user && verifyJson.data.user.id) {
        pm.collectionVariables.set('buyerId', String(verifyJson.data.user.id));
    }
    console.log('✓ buyerToken + refreshToken saved via OTP flow');
}

const json = pm.response.json();
if (json.data) {
    const accessToken = json.data.accessToken || json.data.token;
    const refreshToken = json.data.refreshToken || '';
    pm.collectionVariables.set('sellerToken', accessToken);
    if (refreshToken) pm.collectionVariables.set('refreshToken', refreshToken);
    const decoded = accessToken.split('.')[1];
    const payload = JSON.parse(atob(decoded));
    pm.collectionVariables.set('sellerId', String(payload.sellerId));
    console.log('✓ sellerToken + refreshToken saved (seller id=' + payload.sellerId + ')');
}

